module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);
    reg [7:0] multiplicand;
    reg [7:0] multiplier;
    reg [15:0] partial_product;
    reg [3:0] counter;
    always @(*) begin
        if (counter == 0) begin
            multiplicand = A;
            multiplier = B;
            partial_product = 0;
            counter = 0;
        end else begin
            if (multiplier[0] == 1)
                partial_product = partial_product + (multiplicand << counter);
            multiplier = multiplier >> 1;
            counter = counter + 1;
        end
    end
    always @(posedge clk) begin
        if (counter == 8) begin
            product <= partial_product;
        end
    end
endmodule
